  <div class="card"><div class="card-label">Geschwindigkeit (m/s)</div><div class="card-value">max. ${et?et.maxSpeed.toFixed(1):"-"}</div><div class="card-sub">Durchschnitt: ${et?et.avgSpeed.toFixed(1):"-"} m/s</div></div>
